import { MakeLogicType, actions, afterMount, kea, key, listeners, path, props } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import { ApiConfig } from 'lib/api'

import { outcomesCalculateCreate, outcomesReachedList, outcomesRetrieve } from './generated/api'
import type { OutcomeDefinitionApi, OutcomeLatchApi } from './generated/api.schemas'

export interface OutcomeLogicProps {
    id: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outcomeLogicValues {
    outcome: OutcomeDefinitionApi | null
    outcomeLoading: boolean
    reached: OutcomeLatchApi[]
    reachedLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outcomeLogicActions {
    loadOutcome: () => any
    loadOutcomeFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadOutcomeSuccess: (
        outcome: OutcomeDefinitionApi,
        payload?: any
    ) => {
        outcome: OutcomeDefinitionApi
        payload?: any
    }
    loadReached: () => any
    loadReachedFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadReachedSuccess: (
        reached: OutcomeLatchApi[],
        payload?: any
    ) => {
        reached: OutcomeLatchApi[]
        payload?: any
    }
    recalculate: () => {
        value: true
    }
    refresh: () => {
        value: true
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface outcomeLogicMeta {
    key: any
}

export type outcomeLogicType = MakeLogicType<
    outcomeLogicValues,
    outcomeLogicActions,
    OutcomeLogicProps,
    outcomeLogicMeta
>

export const outcomeLogic = kea<outcomeLogicType>([
    path(['products', 'outcomes', 'frontend', 'outcomeLogic']),
    props({} as OutcomeLogicProps),
    key(({ id }) => id),
    actions({
        recalculate: true,
        refresh: true,
    }),
    loaders(({ props }) => ({
        outcome: [
            null as OutcomeDefinitionApi | null,
            {
                loadOutcome: async () => {
                    return await outcomesRetrieve(String(ApiConfig.getCurrentTeamId()), props.id)
                },
            },
        ],
        reached: [
            [] as OutcomeLatchApi[],
            {
                loadReached: async () => {
                    return await outcomesReachedList(String(ApiConfig.getCurrentTeamId()), props.id)
                },
            },
        ],
    })),
    listeners(({ actions, props }) => ({
        recalculate: async () => {
            await outcomesCalculateCreate(String(ApiConfig.getCurrentTeamId()), props.id)
            lemonToast.info('Recalculation enqueued — refresh in a moment to see new results.')
        },
        refresh: () => {
            actions.loadOutcome()
            actions.loadReached()
        },
    })),
    afterMount(({ actions }) => {
        actions.loadOutcome()
        actions.loadReached()
    }),
])
